#!/usr/bin/env python3
"""Regenerate Star Home Remodeling src/ and root docs with clean UTF-8 (no BOM)."""
from __future__ import annotations

import base64
import json
from pathlib import Path

ROOT = Path(__file__).resolve().parent.parent

_PAYLOAD_B64 = ""

FILES: dict[str, str] = json.loads(base64.b64decode(_PAYLOAD_B64).decode("utf-8"))


def write_utf8(rel_path: str, content: str) -> None:
    path = ROOT.joinpath(*rel_path.split("/"))
    path.parent.mkdir(parents=True, exist_ok=True)
    text = content.lstrip("\ufeff")
    path.write_text(text, encoding="utf-8", newline="\n")


def main() -> None:
    written: list[str] = []
    for rel, content in sorted(FILES.items()):
        write_utf8(rel, content)
        written.append(rel)
    print(f"Wrote {len(written)} files:")
    for rel in written:
        print(f"  - {rel}")


if __name__ == "__main__":
    main()
